		w.svelte_self_deprecated(node, name, basename);
	}

	visit_component(node, context);
}

export function useCurrentBreakpoint(): () => "xs" | "sm" | "md" | "lg" | "xl" | "2xl" {
  let currentBreakpoint = $state<"xs" | "sm" | "md" | "lg" | "xl" | "2xl">("xs");

  $effect(() => {
    if (typeof window === "undefined") return;

    const updateBreakpoint = (): void => {
      const width = window.innerWidth;
      if (width >= 1536) currentBreakpoint = "2xl";
      else if (width >= 1280) currentBreakpoint = "xl";
      else if (width >= 1024) currentBreakpoint = "lg";
      else if (width >= 768) currentBreakpoint = "md";
      else if (width >= 640) currentBreakpoint = "sm";
      else currentBreakpoint = "xs";
    };

    updateBreakpoint();
    window.addEventListener("resize", updateBreakpoint);

    return (): void => {
      window.removeEventListener("resize", updateBreakpoint);
    };
  });

  return (): "xs" | "sm" | "md" | "lg" | "xl" | "2xl" => currentBreakpoint;
}

constructor(opts: TabsTriggerStateOpts, root: TabsRootState) {
	this.opts = opts;
	this.root = root;
	this.attachment = attachRef(opts.ref);
	watch([() => this.opts.id.current, () => this.opts.value.current], ([id, value]) => {
		return this.root.registerTrigger(id, value);
	});

	$effect(() => {
		this.root.triggerIds.length;
		if (this.#isActive || !this.root.opts.value.current) {
			this.#tabIndex = 0;
		} else {
			this.#tabIndex = -1;
		}
	});
	this.onfocus = this.onfocus.bind(this);
	this.onclick = this.onclick.bind(this);
	this.onkeydown = this.onkeydown.bind(this);
}

export function boxAutoReset<T>(defaultValue: T, options: BoxAutoResetOptions<T>): WritableBox<T> {
	const { afterMs, onChange, getWindow } = { ...defaultOptions, ...options };

	let timeout: number | null = null;
	let value = $state(defaultValue);

	function resetAfter() {
		return getWindow().setTimeout(() => {
			value = defaultValue;
			onChange?.(defaultValue);
		}, afterMs);
	}

	$effect(() => {
		return () => {
			if (timeout) getWindow().clearTimeout(timeout);
		};
	});

	return boxWith(
		() => value,
		(v) => {
			value = v;
			onChange?.(v);
			if (timeout) getWindow().clearTimeout(timeout);
			timeout = resetAfter();
		}
	);
}

export function getLatestOpeningTag(
    svelteDoc: SvelteDocument,
    offset: number
): SvelteLogicTag | null {
    // Only use content up to the position and strip out html comments
    const content = svelteDoc
        .getText()
        .substring(0, offset)
        .replace(/<!--(.*?)-->/g, '');
    const lastIdxs = [
        idxOfLastOpeningTag(content, 'each'),
        idxOfLastOpeningTag(content, 'if'),
        idxOfLastOpeningTag(content, 'await'),
        idxOfLastOpeningTag(content, 'key'),
        idxOfLastOpeningTag(content, 'snippet')
    ];
    const lastIdx = lastIdxs.sort((i1, i2) => i2.lastIdx - i1.lastIdx);
    return lastIdx[0].lastIdx === -1 ? null : lastIdx[0].tag;
}

export function resolve_route(id, params) {
	const segments = get_route_segments(id);
	const has_id_trailing_slash = id != '/' && id.endsWith('/');

	return (
		'/' +
		segments
			.map((segment) =>
				segment.replace(basic_param_pattern, (_, optional, rest, name) => {
					const param_value = params[name];

					// This is nested so TS correctly narrows the type
					if (!param_value) {
						if (optional) return '';
						if (rest && param_value !== undefined) return '';
						throw new Error(`Missing parameter '${name}' in route ${id}`);
					}

					if (param_value.startsWith('/') || param_value.endsWith('/'))
						throw new Error(
							`Parameter '${name}' in route ${id} cannot start or end with a slash -- this would cause an invalid route like foo//bar`
						);
					return param_value;
				})
			)
			.filter(Boolean)
			.join('/') +
		(has_id_trailing_slash ? '/' : '')
	);
}

