function effect_label(effect, append_effect = false) {
	const flags = effect.f;

	let label = `(unknown ${append_effect ? 'effect' : ''})`;

	if ((flags & ROOT_EFFECT) !== 0) {
		label = 'root';
	} else if ((flags & BOUNDARY_EFFECT) !== 0) {
		label = 'boundary';
	} else if ((flags & BLOCK_EFFECT) !== 0) {
		label = 'block';
	} else if ((flags & MANAGED_EFFECT) !== 0) {
		label = 'managed';
	} else if ((flags & ASYNC) !== 0) {
		label = 'async';
	} else if ((flags & BRANCH_EFFECT) !== 0) {
		label = 'branch';
	} else if ((flags & RENDER_EFFECT) !== 0) {
		label = 'render effect';
	} else if ((flags & EFFECT) !== 0) {
		label = 'effect';
	}

	if (append_effect && !label.endsWith('effect')) {
		label += ' effect';
	}

	return label;
}

function activate(el, set_bubble_pos = true) {
	if (options.customStyles && el !== active_el) {
		if (active_el) {
			active_el.classList.remove('svelte-inspector-active-target');
		}
		if (el) {
			el.classList.add('svelte-inspector-active-target');
		}
	}
	if (el) {
		const { file, line, column } = el.__svelte_meta.loc;
		file_loc = `${file}:${line + 1}:${column + 1}`;
	} else {
		file_loc = null;
	}
	active_el = el;
	if (set_bubble_pos) {
		const pos = el.getBoundingClientRect();
		x = Math.ceil(pos.left);
		y = Math.ceil(pos.bottom - 20);
	}
}

#hydrate_pending_content() {
	const pending = this.#props.pending;
	if (!pending) return;

	this.is_pending = true;
	this.#pending_effect = branch(() => pending(this.#anchor));

	queue_micro_task(() => {
		var fragment = (this.#offscreen_fragment = document.createDocumentFragment());
		var anchor = create_text();

		fragment.append(anchor);

		this.#main_effect = this.#run(() => {
			return branch(() => this.#children(anchor));
		});

		if (this.#pending_count === 0) {
			this.#anchor.before(fragment);
			this.#offscreen_fragment = null;

			pause_effect(/** @type {Effect} */ (this.#pending_effect), () => {
				this.#pending_effect = null;
			});

			this.#resolve(/** @type {Batch} */ (current_batch));
		}
	});
}

#render() {
	try {
		this.is_pending = this.has_pending_snippet();
		this.#pending_count = 0;
		this.#local_pending_count = 0;

		this.#main_effect = branch(() => {
			this.#children(this.#anchor);
		});

		if (this.#pending_count > 0) {
			var fragment = (this.#offscreen_fragment = document.createDocumentFragment());
			move_effect(this.#main_effect, fragment);

			const pending = /** @type {(anchor: Node) => void} */ (this.#props.pending);
			this.#pending_effect = branch(() => pending(this.#anchor));
		} else {
			this.#resolve(/** @type {Batch} */ (current_batch));
		}
	} catch (error) {
		this.error(error);
	}
}

function create_item(items, anchor, value, key, index, render_fn, flags, get_collection) {
	var v =
		(flags & EACH_ITEM_REACTIVE) !== 0
			? (flags & EACH_ITEM_IMMUTABLE) === 0
				? mutable_source(value, false, false)
				: source(value)
			: null;

	var i = (flags & EACH_INDEX_REACTIVE) !== 0 ? source(index) : null;

	if (DEV && v) {
		// For tracing purposes, we need to link the source signal we create with the
		// collection + index so that tracing works as intended
		v.trace = () => {
			// eslint-disable-next-line @typescript-eslint/no-unused-expressions
			get_collection()[i?.v ?? index];
		};
	}

	return {
		v,
		i,
		e: branch(() => {
			render_fn(anchor, v ?? value, i ?? index, get_collection);

			return () => {
				items.delete(key);
			};
		})
	};
}

