function log_dep(dep) {
	if ((dep.f & DERIVED) !== 0) {
		const derived = /** @type {Derived} */ (dep);

		// eslint-disable-next-line no-console
		console.groupCollapsed(
			`%c$derived %c${dep.label ?? '<unknown>'}`,
			'font-weight: bold; color: CornflowerBlue',
			'font-weight: normal',
			untrack(() => snapshot(derived.v))
		);

		if (derived.deps) {
			for (const d of derived.deps) {
				log_dep(d);
			}
		}

		// eslint-disable-next-line no-console
		console.groupEnd();
	} else {
		// eslint-disable-next-line no-console
		console.log(
			`%c$state %c${dep.label ?? '<unknown>'}`,
			'font-weight: bold; color: CornflowerBlue',
			'font-weight: normal',
			untrack(() => snapshot(dep.v))
		);
	}
}

const getClosestThumb = (e: PointerEvent) => {
	const thumbs = getAllThumbs();
	if (!thumbs) return;
	thumbs.forEach((thumb) => thumb.blur());

	const distances = thumbs.map((thumb) => {
		if ($orientation === 'horizontal') {
			const { left, right } = thumb.getBoundingClientRect();
			return Math.abs(e.clientX - (left + right) / 2);
		} else {
			const { top, bottom } = thumb.getBoundingClientRect();
			return Math.abs(e.clientY - (top + bottom) / 2);
		}
	});

	const thumb = thumbs[distances.indexOf(Math.min(...distances))];
	const index = thumbs.indexOf(thumb);

	return { thumb, index };
};

function get_code_frame(line, column) {
	const lines = state.source_lines;
	const frame_start = Math.max(0, line - 2);
	const frame_end = Math.min(line + 3, lines.length);
	const digits = String(frame_end + 1).length;
	return lines
		.slice(frame_start, frame_end)
		.map((str, i) => {
			const is_error_line = frame_start + i === line;
			const line_num = String(i + frame_start + 1).padStart(digits, ' ');
			if (is_error_line) {
				const indicator =
					' '.repeat(digits + 2 + tabs_to_spaces(str.slice(0, column)).length) + '^';
				return `${line_num}: ${tabs_to_spaces(str)}\n${indicator}`;
			}
			return `${line_num}: ${tabs_to_spaces(str)}`;
		})
		.join('\n');
}

export default async function (config: GenerateConfig): ReturnType<Resource['generate']> {
    const { withRunes, withTs, withProps } = config.kind;
    let template = defaultScriptTemplate;

    if (withRunes && withTs && withProps) {
        template = tsSv5ScriptTemplateProps;
    } else if (withRunes && withTs && !withProps) {
        template = tsSv5ScriptTemplate;
    } else if (withRunes && !withTs && withProps) {
        template = jsSv5ScriptTemplateProps;
    } else if (withRunes && !withTs && !withProps) {
        template = jsSv5ScriptTemplate;
    } else if (!withRunes && withTs) {
        template = tsScriptTemplate;
    } else if (!withRunes && !withTs) {
        template = defaultScriptTemplate;
    }

    return template.trim();
}

